local Renderer = {}; function Renderer:new() local renderer = {widgets = {}, frameCount = 0} setmetatable(renderer, self) self.__index = self return renderer end; function Renderer:addWidget(id, widget) self.widgets[id] = widget end; function Renderer:removeWidget(id) self.widgets[id] = nil end; function Renderer:render() self.frameCount = self.frameCount + 1 for id, widget in pairs(self.widgets) do if widget.render then widget:render() end end end; function Renderer:getFrameCount() return self.frameCount end; return Renderer